import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Zu 1.21.11 portieren","description":"Ein Leitfaden für die Portierung auf die neueste Version von Minecraft.","frontmatter":{"title":"Zu 1.21.11 portieren","description":"Ein Leitfaden für die Portierung auf die neueste Version von Minecraft.","authors":["cassiancc"],"files":[]},"headers":[],"relativePath":"de_de/develop/porting/current.md","filePath":"translated/de_de/develop/porting/current.md","lastUpdated":1770561656000}`);var a={name:`de_de/develop/porting/current.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Zu 1.21.11 portieren <a class="header-anchor" href="#h1" aria-label="Permalink to “Zu 1.21.11 portieren”">​</a></h1><p>Minecraft ist ein Spiel, das sich ständig weiterentwickelt, wobei neue Versionen das Spiel in einer Weise verändern, die sich auf Modder auswirkt. Dieser Artikel deckt die allgemeinen Schritte ab, die man befolgen kann, um seinen Mod auf die neueste stabile Version von Minecraft zu aktualisieren.</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Dieses Dokumentation behandelt die Migration von <strong>1.21.10</strong> auf <strong>1.21.11</strong>. Wenn du nach einer anderen Migration suchst, wechsle mithilfe des Dropdown-Menüs in der oberen rechten Ecke zur Zielversion.</p></div><h2 id="build-script" tabindex="-1">Das Buildskript aktualisieren <a class="header-anchor" href="#build-script" aria-label="Permalink to “Das Buildskript aktualisieren”">​</a></h2><p>Beginne damit, die Dateien <code>gradle/wrapper/gradle-wrapper.properties</code>, <code>gradle.properties</code> und <code>build.gradle</code> deines Mods auf die neuesten Versionen zu aktualisieren:</p><ol><li>Aktualisiere Gradle auf die aktuellste Version, indem du den folgenden Befehl ausführst: <code>./gradlew wrapper --gradle-version latest</code></li><li>Hebe Minecraft, den Fabric Loader, Fabric Loom und die Fabric API an, entweder in der <code>gradle.properties</code> (empfohlen) oder in der <code>build.gradle</code>. Die empfohlenen Versionen der Fabric-Komponenten findest du auf der <a href="https://fabricmc.net/develop/" target="_blank" rel="noreferrer">Fabric Develop-Website</a>.</li><li>Aktualisiere Gradle, indem du auf die Schaltfläche zur Aktualisierung in der oberen rechten Ecke von IntelliJ IDEA klickst. Wenn diese Schaltfläche nicht sichtbar ist, kannst du das Leeren der Caches erzwingen, indem du <code>./gradlew --refresh-dependencies</code> ausführst.</li></ol><h2 id="porting-guides" tabindex="-1">Den Code aktualisieren <a class="header-anchor" href="#porting-guides" aria-label="Permalink to “Den Code aktualisieren”">​</a></h2><p>Nachdem das Buildskript auf 1.21.11 aktualisiert wurde, kannst du nun deinen Mod durchgehen und allen geänderten Code aktualisieren, um ihn mit der neuen Version kompatibel zu machen.</p><p>Um dir bei der Aktualisierung zu helfen, dokumentieren Modder die Änderungen, auf die sie gestoßen sind, in Artikeln wie dem Fabric Blog und den Anleitungen zur Portierung von NeoForge.</p><ul><li><a href="https://fabricmc.net/2025/12/05/12111.html" target="_blank" rel="noreferrer"><em>Fabric for Minecraft 1.21.11</em> im Fabric-Blog</a> enthält eine allgemeine Erläuterung der Änderungen, die in 1.21.11 an der Fabric-API vorgenommen wurden.</li><li><a href="https://www.minecraft.net/en-us/article/minecraft-java-edition-1-21-11" target="_blank" rel="noreferrer"><em>Minecraft: Java Edition 1.21.11</em> im Minecraft-Blog</a> ist die offizielle Übersicht an Funktionen, die in 1.21.11 eingeführt wurden.</li><li><a href="https://minecraft.wiki/w/Java_Edition_1.21.11" target="_blank" rel="noreferrer"><em>Java Edition 1.21.11</em> im Minecraft Wiki</a> ist eine inoffizielle Zusammenfassung der Inhalte des Updates.</li><li><a href="https://www.youtube.com/watch?v=5yY25GoWQhs&amp;pp=0gcJCSkKAYcqIYzv" target="_blank" rel="noreferrer">slicedlime&#39;s Data &amp; Resource Pack News in Minecraft 1.21.11</a> deckt Informationen ab, die für die Aktualisierung der Daten- und ressourcenpaketgesteuerten Inhalte deines Mods relevant sind.</li><li><a href="https://github.com/neoforged/.github/blob/main/primers/1.21.11/index.md" target="_blank" rel="noreferrer">NeoForge&#39;s <em>Minecraft 1.21.10 -&gt; 1.21.11 Mod Migration Primer</em></a> deckt die Migration mit Fokus auf Änderungen des Vanilla Code von 1.21.10 zu 1.21.11 ab. <ul><li>Bitte beachten, dass es sich bei dem verlinkten Artikel um Material von Dritten handelt, das nicht von Fabric gepflegt wird. Es unterliegt dem Urheberrecht von @ChampionAsh5357 und ist lizenziert unter <a href="https://creativecommons.org/licenses/by/4.0/" target="_blank" rel="noreferrer">Creative Commons Attribution 4.0 International</a>.</li></ul></li></ul>`,10)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};